using UnityEngine;
using Climbing;
using UnityEditor;

public class ColliderFixer
{
    public static string Run()
    {
        ClimbController cc = Object.FindObjectOfType<ClimbController>();
        if (cc == null) return "No player found in scene.";

        GameObject pm = cc.gameObject;
        CapsuleCollider col = pm.GetComponent<CapsuleCollider>();
        if (col == null) return "CapsuleCollider not found on " + pm.name;

        string report = $"--- Before Fix: Center={col.center}, Height={col.height}, Radius={col.radius} ---\n";

        // Standard humanoid settings: 
        // Height 1.8m, Radius 0.3m, Center at 0.9m (half height)
        col.height = 1.8f;
        col.center = new Vector3(0, 0.9f, 0);
        col.radius = 0.3f;

        report += $"--- After Fix: Center={col.center}, Height={col.height}, Radius={col.radius} ---\n";

        // Also check if there's a second collider (some controllers use two)
        ThirdPersonController tpc = pm.GetComponent<ThirdPersonController>();
        if (tpc != null) {
            if (tpc.normalCapsuleCollider != null) {
                tpc.normalCapsuleCollider.height = 1.8f;
                tpc.normalCapsuleCollider.center = new Vector3(0, 0.9f, 0);
                report += "- Updated TPC normalCapsuleCollider\n";
            }
            if (tpc.slidingCapsuleCollider != null) {
                tpc.slidingCapsuleCollider.height = 0.9f; // Slide is usually shorter
                tpc.slidingCapsuleCollider.center = new Vector3(0, 0.45f, 0);
                report += "- Updated TPC slidingCapsuleCollider\n";
            }
        }

        return report;
    }
}
